// For each user, gather today's activity
const users = $input.all().map(i => i.json);
const results = [];

for (const user of users) {
  // In production, these would be separate PostgreSQL queries:
  // 1. Today's trades for this user
  // 2. Alerts triggered today for this user
  // 3. Current holdings + live prices
  // 4. Patterns detected today
  // 5. Prediction status updates

  results.push({
    user_id: user.user_id,
    chat_id: user.alerts_chat_id || user.private_chat_id,
    display_name: user.display_name
  });
}

return results.map(r => ({ json: r }));

// Build EOD summary with live closing prices
// In production: fetch closing prices from Kite, calculate day P&L
const holdings = $input.all().map(i => i.json);
const user = $('Gather Day Data').item.json;

if (holdings.length === 0) {
  return [{
    json: {
      chat_id: user.chat_id,
      message: `📊 *EOD Summary — ${user.display_name}*\n\nNo holdings to report. Add trades to start tracking!`
    }
  }];
}

// Template message — in production, fill with actual closing prices
const msg = `🔔 *End of Day Summary*\n` +
  `📅 ${new Date().toISOString().split('T')[0]}\n\n` +
  `📊 *Portfolio: ${holdings.length} stocks*\n` +
  holdings.map(h => 
    `• ${h.symbol}: ${h.net_quantity} shares @ ₹${h.avg_buy_price}`
  ).join('\n') +
  `\n\n💡 _Closing prices will be fetched from Kite API_\n` +
  `\n⚠️ Technical analysis only. Not financial advice.`;

return [{ json: { chat_id: user.chat_id, message: msg } }];
